// Echo webhook — connectivity canary.
// If this responds, the OpenClaw -> n8n integration layer works.

const input = $input.first().json;
const body = input.body || input;
const now = new Date().toISOString();

// Summarize the incoming payload
const keys = Object.keys(body);
const summary = keys.length > 0
  ? keys.map(k => `${k}=${JSON.stringify(body[k])}`).join(', ')
  : '(empty payload)';

return [{
  json: {
    status: 'ok',
    message: `n8n received: ${summary}`,
    receivedAt: now,
    payloadKeys: keys,
    echo: body
  }
}];
